final:
module top_module(
    input [3:0] a,
    input [3:0] b,
    input carry_in,
    output [3:0] sum,
    output carry_out
);

    // Intermediate full adder sum and carry outputs
    wire [4:0] sum_temp;

    // Perform addition with carry-in
    assign sum_temp = a + b + carry_in;

    // Assign the sum and carry-out
    assign sum = sum_temp[3:0];
    assign carry_out = sum_temp[4];

endmodule
